// TestUpsertBatch_TypedFailureDoesNotStrandIndexedAssetsGeneric exercises
// the savepoint isolation around the typed-table dispatch. The fixture omits
// the NOT NULL parent FK column so the typed insert fails; the savepoint
// rolls back only the typed projection. The generic resources row inserted
// just before must survive. Regression for issue #1392, where a single
// outer transaction caused typed-table failures to cascade and silently
// discard every successfully fetched API row.
func TestUpsertBatch_TypedFailureDoesNotStrandIndexedAssetsGeneric(t *testing.T) {
	dbPath := filepath.Join(t.TempDir(), "data.db")
	s, err := Open(dbPath)
	if err != nil {
		t.Fatalf("open: %v", err)
	}
	defer s.Close()

	// Items deliberately omit "indexes_id" so the typed NOT NULL
	// constraint fires.
	items := []json.RawMessage{
		json.RawMessage(`{"id": "orphan-001"}`),
		json.RawMessage(`{"id": "orphan-002"}`),
		json.RawMessage(`{"id": "orphan-003"}`),
	}
	stored, extractFailures, err := s.UpsertBatch("indexed_assets", items)
	if err != nil {
		t.Fatalf("UpsertBatch: %v (typed-table failure must not propagate)", err)
	}
	if stored != len(items) {
		t.Fatalf("stored = %d, want %d (generic resources rows must land even when typed table fails)", stored, len(items))
	}
	if extractFailures != 0 {
		t.Fatalf("extractFailures = %d, want 0", extractFailures)
	}

	db := s.DB()

	var generic int
	if err := db.QueryRow(`SELECT COUNT(*) FROM resources WHERE resource_type = ?`, "indexed_assets").Scan(&generic); err != nil {
		t.Fatalf("count resources: %v", err)
	}
	if generic != len(items) {
		t.Fatalf("resources count = %d, want %d (savepoint rollback must not undo generic insert)", generic, len(items))
	}

	var typed int
	typedQuery := fmt.Sprintf(`SELECT COUNT(*) FROM "%s"`, "indexed_assets")
	if err := db.QueryRow(typedQuery).Scan(&typed); err != nil {
		t.Fatalf("count indexed_assets: %v", err)
	}
	if typed != 0 {
		t.Fatalf("indexed_assets count = %d, want 0 (typed insert violated NOT NULL on %q)", typed, "indexes_id")
	}
}

// TestUpsertBatch_SetsIndexedAssetsParentID verifies that dependent-resource
// sync (which injects parent_id into each item's JSON) populates the typed
// parent_id column when items go through UpsertBatch. Regression for issue #268.
func TestUpsertBatch_SetsIndexedAssetsParentID(t *testing.T) {
	dbPath := filepath.Join(t.TempDir(), "data.db")
	s, err := Open(dbPath)
	if err != nil {
		t.Fatalf("open: %v", err)
	}
	defer s.Close()

	items := []json.RawMessage{
		json.RawMessage(`{"id": "child-001", "indexes_id": "parent-A", "parent_id": "parent-A"}`),
		json.RawMessage(`{"id": "child-002", "indexes_id": "parent-A", "parent_id": "parent-A"}`),
		json.RawMessage(`{"id": "child-003", "indexes_id": "parent-B", "parent_id": "parent-B"}`),
	}
	if _, _, err := s.UpsertBatch("indexed_assets", items); err != nil {
		t.Fatalf("UpsertBatch: %v", err)
	}

	db := s.DB()

	var matchedA int
	parentQuery := fmt.Sprintf(`SELECT COUNT(*) FROM "%s" WHERE parent_id = ?`, "indexed_assets")
	if err := db.QueryRow(parentQuery, "parent-A").Scan(&matchedA); err != nil {
		t.Fatalf("count by parent_id: %v", err)
	}
	if matchedA != 2 {
		t.Fatalf("parent_id=parent-A count = %d, want 2 (parent_id column not populated)", matchedA)
	}
}

